7	import { fontAssets } from '@/design/typography';
8	import { ToastProvider } from '@/components/primitives/Toast';
9	
10	// Hold the splash screen until custom fonts register — text with an unregistered
11	// fontFamily silently falls back to System on iOS and the swap is visible to the user.
12	// Promise rejects if the splash was already dismissed (fast-refresh, dev reloads) —
13	// swallow so Metro doesn't see an unhandled rejection.
14	SplashScreen.preventAutoHideAsync().catch(() => {});
15	
16	export default function RootLayout() {
17	  const [fontsLoaded, fontError] = useFonts(fontAssets);
18	
19	  useEffect(() => {
20	    if (fontsLoaded || fontError) {
21	      SplashScreen.hideAsync();
22	    }
23	  }, [fontsLoaded, fontError]);
24	
25	  if (!fontsLoaded && !fontError) {
26	    return null;
27	  }
28	
29	  return (
30	    <GestureHandlerRootView style={{ flex: 1 }}>
31	      <ToastProvider>
32	        <Slot />
33	      </ToastProvider>
34	      <StatusBar style="auto" />
35	    </GestureHandlerRootView>
36	  );
37	}
